<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Http\Requests\Payroll\StorePayrollPeriodRequest; use App\Models\Payroll\PayrollPeriod; use Illuminate\Http\RedirectResponse; use Illuminate\View\View; class PayrollPeriodController extends Controller{public function index():View{return view('payroll.periods.index',['title'=>'Periode Payroll','periods'=>PayrollPeriod::latest()->paginate(15)]);} public function create():View{return view('payroll.periods.form',['title'=>'Tambah Periode Payroll','period'=>new PayrollPeriod]);} public function store(StorePayrollPeriodRequest $r):RedirectResponse{PayrollPeriod::create($r->validated()+['created_by'=>$r->user()->id,'status'=>'draft']);return redirect()->route('payroll.periods.index')->with('status','Periode Payroll dibuat.');} public function show(PayrollPeriod $period):View{return view('payroll.periods.show',['title'=>'Detail Periode Payroll','period'=>$period]);}}
